solution_code:
import numpy as np

class HierarchicalChunker:
    def __init__(self, parent_size: int, child_size: int, overlap: int = 0):
        self.parent_size = parent_size
        self.child_size = child_size
        self.overlap = overlap
        self.child_index = []   # list of {'id', 'tokens', 'parent_id', 'embed'}
        self.parent_store = {}  # parent_id -> chunk dict

    def _make_chunks(self, tokens, chunk_size, overlap):
        if len(tokens) == 0:
            return []
        if len(tokens) <= chunk_size:
            return [tokens[:]]
        stride = chunk_size - overlap
        chunks = []
        start = 0
        while start < len(tokens):
            chunks.append(tokens[start:start + chunk_size])
            if start + chunk_size >= len(tokens):
                break
            start += stride
        return chunks

    def chunk_document(self, doc_tokens: list, doc_id: str) -> tuple:
        parent_chunks = []
        child_chunks = []
        parent_token_chunks = self._make_chunks(doc_tokens, self.parent_size, 0)
        for p_idx, p_tokens in enumerate(parent_token_chunks):
            parent_id = f"{doc_id}_p{p_idx}"
            parent = {'id': parent_id, 'tokens': p_tokens, 'parent_id': None}
            parent_chunks.append(parent)
            child_token_chunks = self._make_chunks(p_tokens, self.child_size, self.overlap)
            for c_idx, c_tokens in enumerate(child_token_chunks):
                child_id = f"{parent_id}_c{c_idx}"
                child = {'id': child_id, 'tokens': c_tokens, 'parent_id': parent_id}
                child_chunks.append(child)
        return parent_chunks, child_chunks

    def add_document(self, doc_tokens: list, doc_id: str, doc_embeds: np.ndarray) -> None:
        parents, children = self.chunk_document(doc_tokens, doc_id)
        for p in parents:
            self.parent_store[p['id']] = p
        for i, child in enumerate(children):
            if i < len(doc_embeds):
                child['embed'] = doc_embeds[i]
                self.child_index.append(child)

    def retrieve(self, query_embed: np.ndarray, top_k: int = 3) -> list:
        if not self.child_index:
            return []
        q_norm = query_embed / (np.linalg.norm(query_embed) + 1e-10)
        embeds = np.stack([c['embed'] for c in self.child_index])
        norms = np.linalg.norm(embeds, axis=1, keepdims=True)
        embeds_norm = embeds / (norms + 1e-10)
        sims = embeds_norm @ q_norm
        sorted_indices = np.argsort(-sims)
        seen_parents = set()
        result = []
        for idx in sorted_indices:
            child = self.child_index[int(idx)]
            parent_id = child['parent_id']
            if parent_id not in seen_parents:
                seen_parents.add(parent_id)
                result.append(self.parent_store[parent_id])
                if len(result) >= top_k:
                    break
        return result

