chunker = HierarchicalChunker(parent_size=6, child_size=2)
tokens = list(range(6))
parents, children = chunker.chunk_document(tokens, 'doc')
parent_ids = {p['id'] for p in parents}
for child in children:
    assert child['parent_id'] in parent_ids, f"Child's parent_id {child['parent_id']} not in parents"

chunker = HierarchicalChunker(parent_size=8, child_size=3)
tokens = list(range(8))
parents, children = chunker.chunk_document(tokens, 'doc')
# All child tokens should be a subset of their parent's tokens
parent_map = {p['id']: p['tokens'] for p in parents}
for child in children:
    parent_tokens = parent_map[child['parent_id']]
    for tok in child['tokens']:
        assert tok in parent_tokens, f"Child token {tok} not in parent {parent_tokens}"
